async function get(table, query = 'select=*&order=created_at.desc&limit=50') {
  return await this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/rest/v1/${table}?${query}`,
    headers: {
      apikey: key,
      Authorization: `Bearer ${key}`,
    },
    json: true,
  });
}

const [clinics, nps, reviews, enps, mentions, recall, inbox] = await Promise.all([
  get.call(this, 'clinics', 'select=id,name,slug,whatsapp_phone,booking_url,created_at,logo_url,website_url,email,address,google_review_url,google_maps_url,trustpilot_url,sikayetvar_url,website_reviews_url,google_rating,google_review_count&order=name.asc'),
  get.call(this, 'nps_responses'),
  get.call(this, 'google_reviews'),
  get.call(this, 'enps_responses'),
  get.call(this, 'reputation_mentions'),
  get.call(this, 'recall_campaigns'),
  get.call(this, 'inbox_messages'),
]);

return [{ json: { clinics, nps, reviews, enps, mentions, recall, inbox } }];
